import axios from 'axios';

const signin = async ( {email, password} ) =>{
    try{
        const response = await axios.post('/auth/signin',{
            email, password
        });

        response

    } catch(err){
        if(err.response){
            return err.response.data;
        }

        return {
            success: false,
            message: "서버오류"
        }
    }
}


export default signin;
